# 六、功能实现

## 6.1 搜索

```bash
# 先安装依赖
npm install hexo-generator-search --save
```

```yml
# _config.yml 增加配置
search:
  path: search.json
  field: post
```

1. 设置项目 _config.yml - search - path 改为 json 格式，即 search.json
2. 在 source/js 下放入 jquery.js，head.ejs 使用 `<%- js('js/jquery.js') %>` 引入 JQuery，用来实现 scripts/search.js，从 json 中检索数据
3. source/js/search.js 中，我们通过 searchFunc 函数实现 json 搜索，同样需要引入
4. 创建 search.ejs 及其样式，包含相应的输入框，和结果展示，并调用 search.js/searchFunc 进行搜索
5. searchFunc 会注册 input 事件，并将结果渲染到制定的 dom 中。我们通过合理的添加一些样式文件来实现弹窗形式的搜索组件(不再赘述)

```js
// source/js/search.js
var searchFunc = function (path, search_id, content_id) {
  // 'use strict';
  $.ajax({
    url: path,
    dataType: 'json',
    success: function (datas) {
      console.log(datas);
      var $input = document.getElementById(search_id);
      var $resultContent = document.getElementById(content_id);
      $input.addEventListener('input', function () {
        var str = '<ul class="search-result-list">';
        var keywords = this.value
          .trim()
          .toLowerCase()
          .split(/[\s\-]+/);
        $resultContent.innerHTML = '';
        if (this.value.trim().length <= 0) {
          return;
        }
        // perform local searching
        datas.forEach(function (data) {
          var isMatch = true;
          var content_index = [];
          var data_title = data.title.trim().toLowerCase();
          var data_content = data.content
            .trim()
            .replace(/<[^>]+>/g, '')
            .toLowerCase();
          var data_url = data.url;
          var index_title = -1;
          var index_content = -1;
          var first_occur = -1;
          // only match artiles with not empty titles and contents
          if (data_title != '' && data_content != '') {
            keywords.forEach(function (keyword, i) {
              index_title = data_title.indexOf(keyword);
              index_content = data_content.indexOf(keyword);
              if (index_title < 0 && index_content < 0) {
                isMatch = false;
              } else {
                if (index_content < 0) {
                  index_content = 0;
                }
                if (i == 0) {
                  first_occur = index_content;
                }
              }
            });
          }
          // show search results
          if (isMatch) {
            str += "<li><a href='" + data_url + "' class='search-result-title'>" + data_title + '</a>';
            var content = data.content.trim().replace(/<[^>]+>/g, '');
            if (first_occur >= 0) {
              // cut out 100 characters
              var start = first_occur - 20;
              var end = first_occur + 80;
              if (start < 0) {
                start = 0;
              }
              if (start == 0) {
                end = 100;
              }
              if (end > content.length) {
                end = content.length;
              }
              var match_content = content.substr(start, end);
              // highlight all keywords
              keywords.forEach(function (keyword) {
                var regS = new RegExp(keyword, 'gi');
                match_content = match_content.replace(regS, '<em class="search-keyword">' + keyword + '</em>');
              });

              str += '<p class="search-result">' + match_content + '...</p>';
            }
            str += '</li>';
          }
        });
        str += '</ul>';
        $resultContent.innerHTML = str;
      });
    },
  });
};
```

```html
<!-- layout/_partial/search.ejs -->
<button id="btnSearch" class="search-btn">搜索</button>
<div id="searchContainer" class="search-container">
  <div id="searchContent" class="search-content">
    <div class="search-input">
      <input id="searchInput" type="text" placeholder="查找文章" />
    </div>
    <div id="searchResult" class="search-result"></div>
  </div>
</div>
<script>
  // 点击搜索打开搜索弹窗
  btnSearch.addEventListener('click', function () {
    $('.search-container').addClass('show-search');
  });
  // 阻止冒泡，防止点击弹窗内容触发弹窗关闭
  searchContent.addEventListener('click', function (e) {
    e.stopPropagation();
  });
  // 关闭搜索弹窗
  searchContainer.addEventListener('click', function () {
    $('#searchInput').val('');
    $('#searchResult').empty();
    $('.search-container').removeClass('show-search');
  });
  // 注册搜索函数
  searchFunc('search.json', 'searchInput', 'searchResult');
</script>

```

